INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (184, 'b2991f37-ff7d-4071-b700-2aa547cf7fba', '你好', '你好！我是焦化行业的专家，专注于焦炭生产、炼焦工艺、设备维护以及环保技术等方面。如果你有任何关于焦化行业的问题，比如焦炉操作、煤气净化、焦炭质量提升、节能减排技术等，都可以随时问我。我会尽力提供详细、专业的解答。你现在有什么具体的问题或需求吗？', '2025-03-19 14:27:21');
INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (185, 'ff22ef2a-bb45-4361-a54f-ce086f46dc00', '', '您好！我是焦化大语言智能问答与分析系统DeepCoke，有什么可以帮助你的？', '2025-03-19 14:27:21');
INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (186, 'ff22ef2a-bb45-4361-a54f-ce086f46dc00', '', 'Thank you for the introduction! As an expert in the coking industry, I can provide insights and information on various aspects of coke production, its applications, and related technologies. The coking industry primarily involves the conversion of coal into coke, a carbon-rich material used in blast furnaces for iron and steel production. Here are some key areas I can assist with:\n\n1. **Coke Production Process**: \n   - **Coking Coal Selection**: Understanding the types of coal suitable for coking.\n   - **Coke Ovens**: Design, operation, and maintenance of coke ovens.\n   - **By-Products**: Recovery and utilization of by-products like coal tar, ammonia, and benzene.\n\n2. **Environmental and Safety Considerations**:\n   - Emission control technologies.\n   - Waste management and recycling.\n   - Safety protocols in coke plants.\n\n3. **Market and Economic Aspects**:\n   - Trends in the global coke market.\n   - Cost analysis and economic viability of coke production.\n   - Impact of regulatory changes on the industry.\n\n4. **Technological Advancements**:\n   - Innovations in coke production technology.\n   - Automation and digitalization in coke plants.\n   - Research and development in the field.\n\n5. **Applications of Coke**:\n   - Use in blast furnaces for iron and steel production.\n   - Other industrial applications of coke.\n\nFeel free to ask any specific questions or request detailed information on any of these topics!', '2025-03-19 14:27:42');
INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (187, 'ff22ef2a-bb45-4361-a54f-ce086f46dc00', '没有什么需求。', '好的，如果您未来有任何关于炼焦行业的需求或问题，例如焦炭生产工艺、设备维护、环保技术、市场趋势等方面的咨询，随时可以联系我。我会尽力为您提供专业的解答和建议。祝您一切顺利！', '2025-03-19 14:27:55');
