INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (217, '132a8153-201e-46cb-85e8-58913438371a', '什么是焦炭的CRI和CSR？', '焦炭的CRI（Coke Reactivity Index，焦炭反应性指数）和CSR（Coke Strength after Reaction，焦炭反应后强度）是评估焦炭在高炉中性能的两个重要指标。\n\n1. **CRI（焦炭反应性指数）**：\n   - **定义**：CRI是指焦炭在一定条件下与二氧化碳反应的能力，通常以焦炭在高温下与CO₂反应后的质量损失百分比来表示。\n   - **意义**：CRI值越低，表示焦炭在高炉中与CO₂反应的能力越弱，焦炭在高炉中的稳定性越好。高CRI值可能导致焦炭在高炉中过早消耗，影响高炉的稳定运行。\n\n2. **CSR（焦炭反应后强度）**：\n   - **定义**：CSR是指焦炭在与CO₂反应后，经过一定强度的机械冲击后仍能保持的强度，通常以焦炭在反应后经过转鼓试验后的粒度保持率来表示。\n   - **意义**：CSR值越高，表示焦炭在高炉中经过反应后仍能保持较高的强度，有利于维持高炉的透气性和稳定性。低CSR值可能导致焦炭在高炉中粉化，影响高炉的运行效率。\n\n**总结**：\n- **CRI**：衡量焦炭与CO₂反应的能力，值越低越好。\n- **CSR**：衡量焦炭反应后的强度，值越高越好。\n\n这两个指标共同决定了焦炭在高炉中的表现，是焦炭质量评估的重要参数。', '2025-03-20 06:19:45');
INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (218, '132a8153-201e-46cb-85e8-58913438371a', '回答的挺好的。', '谢谢您的肯定！如果您有任何关于焦化行业、能源技术或其他相关领域的问题，欢迎随时提问，我会尽力为您提供详细和专业的解答。', '2025-03-20 06:19:59');
