INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (223, '37c3c2ba-e3c7-4e76-8af2-b3f58ce2ad1a', '什么是CRI？', 'CRI通常指的是“焦炭反应性指数”（Coke Reactivity Index），这是评估焦炭在高温下与二氧化碳反应的能力的一个指标。CRI值越低，表示焦炭在高温下的稳定性越好，反应性越低。这对于高炉操作非常重要，因为高炉中焦炭需要保持一定的结构强度以支撑炉料，同时其反应性也会影响高炉的还原效率和能耗。CRI的测定通常涉及将焦炭样品暴露在高温下的二氧化碳环境中，测量其重量损失来评估反应性。', '2025-03-20 06:51:30');
