INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (256, '398ee61c-27df-4a9c-9da5-8ed48df6bcb1', '什么是CRI和CSR？', 'CRI（Coke Reactivity Index，焦炭反应性指数）和CSR（Coke Strength after Reaction，焦炭反应后强度）是评估焦炭在高炉中性能的两个重要指标。\n\n1. **CRI（焦炭反应性指数）**：\n   - **定义**：CRI是指焦炭在高温下与二氧化碳反应的能力，通常以焦炭在特定条件下与CO₂反应后失重的百分比来表示。\n   - **意义**：CRI值越低，表示焦炭在高炉中与CO₂反应的能力越弱，焦炭在高炉中的消耗量越少，有利于提高高炉的效率和降低生产成本。\n\n2. **CSR（焦炭反应后强度）**：\n   - **定义**：CSR是指焦炭在与CO₂反应后，经过一定强度的机械冲击后仍能保持的强度，通常以焦炭在反应后经过转鼓试验后的粒度保持率来表示。\n   - **意义**：CSR值越高，表示焦炭在高炉中经过反应后仍能保持较高的强度，有利于维持高炉的透气性和稳定性，从而提高高炉的生产效率。\n\n这两个指标通常用于焦炭的质量控制和高炉操作的优化。低CRI和高CSR的焦炭被认为是高质量焦炭，能够提高高炉的效率和降低能耗。', '2025-03-20 15:25:51');
