INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (265, '4a6c33be-7161-48b8-bc8c-c7ba93c35e28', '什么是CRI？', 'CRI是焦炭反应性指数（Coke Reactivity Index）的缩写，用于评估焦炭在高炉中的反应性能。CRI值越低，表示焦炭在高炉中的反应性越弱，通常意味着焦炭质量越好，能够更有效地支持高炉的稳定运行。CRI的测定通常涉及将焦炭样品暴露在二氧化碳气体中，测量其反应后的失重情况。', '2025-03-21 00:07:29');
