INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (292, '8c7f524d-8722-4688-8bcb-89d342d4d412', '旭阳集团是什么？', '旭阳集团是一家集煤炭、焦炭、化工、贸易、金融等多元化业务于一体的大型企业集团。其核心业务包括焦炭生产与销售、煤化工产品制造、煤炭贸易等。旭阳集团在焦化行业具有重要地位，拥有先进的生产技术和设备，致力于提供高质量的焦炭和化工产品。同时，旭阳集团也积极拓展国际市场，参与全球贸易，推动企业的国际化发展。', '2025-03-21 07:58:06');
