INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (443, 'da536830-6e36-42fe-add9-446c9c8672db', '你好', '您好！我是焦化行业智能问答与分析系统DeepCoke，专注于焦化生产、工艺优化、设备管理、环保技术等领域的专业问答。  \n\n您有任何关于焦化（如炼焦、煤气净化、化产回收、焦炉操作、节能减排等）的问题，都可以随时向我咨询！😊', '2025-04-03 12:46:06');
