INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (462, '6ad64464-f32b-45c8-8141-e5776e66570f', 'Hi, who are you ?', 'Hello! I\'m **DeepCoke**, an AI-powered Q&A and analysis system specialized in **coking (焦化)** technology and related industrial processes. I was developed by **Suzhou Longtai Hydrogen-Energy Technology Co., Ltd.** to assist with technical queries, data analysis, and problem-solving in the coking industry.  \n\nHow can I help you with coking-related topics today? 😊  \n\n(*Note: My expertise focuses on coking—other energy technologies are outside my scope.*)', '2025-04-09 14:36:00');
INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (463, '6ad64464-f32b-45c8-8141-e5776e66570f', 'Hi, who are you ?', 'Hello again! I\'m **DeepCoke**, your dedicated AI assistant for all things related to **coking (焦化) technology and industrial processes**. Developed by **Suzhou Longtai Hydrogen-Energy Technology Co., Ltd.**, my core focus is to provide:  \n\n- **Technical Q&A** (e.g., coke oven operations, by-product recovery)  \n- **Data Analysis** (e.g., $$ \\text{Coke Yield} = \\frac{\\text{Dry Coke Output}}{\\text{Dry Coal Input}} \\times 100\\% $$)  \n- **Process Optimization** (e.g., combustion efficiency, emissions control)  \n\nLet me know how I can assist with your coking-specific questions! 🔥  \n\n(*Reminder: My expertise is strictly coking—I won’t discuss hydrogen/other energy fields.*)', '2025-04-09 14:36:14');
INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (464, '6ad64464-f32b-45c8-8141-e5776e66570f', 'What is the CRI?', '**CRI (Coke Reactivity Index, 焦炭反应性指数)** is a critical parameter in coking that measures the **reactivity of coke with CO₂** under high temperatures (typically at $$ 1100^\\circ \\text{C} $$). It reflects coke’s ability to resist gasification in blast furnaces, directly impacting ironmaking efficiency.  \n\n### Key Points:  \n1. **Definition**:  \n   $$ \\text{CRI} = \\frac{\\text{Weight Loss of Coke after CO₂ Reaction}}{\\text{Initial Coke Weight}} \\times 100\\% $$  \n\n2. **Test Method**:  \n   - Coke samples are heated to $$ 1100^\\circ \\text{C} $$ in a CO₂ atmosphere for 2 hours.  \n   - Weight loss (%) quantifies reactivity.  \n\n3. **Industry Standards**:  \n   - **Lower CRI** = Better coke quality (less reactive, more stable in blast furnaces).  \n   - Typical range: **20–35%** (varies by coal blend and coking conditions).  \n\n4. **Relationship with CSR (Coke Strength after Reaction)**:  \n   - CRI and CSR are inversely correlated (e.g., high CRI often means low CSR).  \n\nNeed data interpretation or optimization tips? Let me know! 🚀  \n\n(*Note: CRI is specific to metallurgical coke—not applicable to other carbon materials.*)', '2025-04-09 14:36:45');
INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (465, '6ad64464-f32b-45c8-8141-e5776e66570f', 'How to test it?', '### **How to Test CRI (Coke Reactivity Index)**  \n\nCRI testing follows standardized methods (e.g., **ISO 18894**, **GB/T 4000-2017** in China). Below is the step-by-step procedure:  \n\n---\n\n#### **1. Sample Preparation**  \n- Collect **200 g** of coke particles (size: **19–21 mm**).  \n- Dry at **105–110°C** to remove moisture.  \n\n#### **2. Test Equipment**  \n- **Reactivity Furnace**: Maintains **1100 ± 5°C** with CO₂ flow.  \n- **Balance**: Precision ±0.01 g.  \n- **CO₂ Gas**: Purity ≥99.9%.  \n\n#### **3. Test Procedure**  \n1. **Weigh Initial Sample**: Record dry coke weight (*W₁*).  \n2. **Heat in N₂ Atmosphere**:  \n   - Ramp to **1100°C** (hold for 30 min) to remove volatile matter.  \n3. **Switch to CO₂**:  \n   - Flow rate: **5 L/min** for **2 hours** (reactivity phase).  \n4. **Cool & Weigh Residue**:  \n   - Cool in N₂, then weigh reacted coke (*W₂*).  \n\n#### **4. Calculate CRI**  \n$$  \n\\text{CRI} = \\frac{W_1 - W_2}{W_1} \\times 100\\%  \n$$  \n*(Example: If 100 g coke loses 25 g, CRI = 25%)*  \n\n#### **5. Complementary CSR Test**  \n- The reacted coke is then tumbled in a drum (600 revolutions, **GB/T 4000-2017**) to determine **CSR** (measures post-reaction strength).  \n\n---\n\n### **Key Notes**  \n- **Repeatability**: Results should vary < **2%** for the same sample.  \n- **Safety**: Use gas detectors (CO₂ leakage risk).  \n- **Standards**: Always refer to regional norms (e.g., ISO, ASTM, GB).  \n\nNeed help interpreting your CRI/CSR results? Share your data! 🔍', '2025-04-09 14:37:19');
