INSERT INTO `messages` (`id`, `session_id`, `user_message`, `bot_response`, `timestamp`) VALUES (467, '8ff10283-e206-41a0-a787-dbeb52d03cbf', '你好', '您好！我是DeepCoke，专注于焦化领域的大语言智能问答与分析系统。如果您有任何关于焦化工艺、设备、生产优化或技术改进的问题，欢迎随时向我咨询。我会尽力为您提供专业、准确的解答。  \n\n请问您想了解焦化行业的哪方面内容？', '2025-07-22 02:25:36');
